  ('disabled-6e2f88c7-moex-00103', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-110-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'essay', '甲係國軍退除役官兵輔導委員會臺北市榮民服務處（以下簡稱臺北市榮服
處）服務組輔導員，臺北市榮服處以民國110 年03 月 25日北市榮人字第
A號考績通知書核布甲 109年年終考績考列乙等，甲不服，依我國現行法
制及實務，甲應如何提起救濟？（25分）
【參考法條】
公務人員考績法第 5 條第 1項：「年終考績應以平時考核為依據。平時考
核就其工作、操行、學識、才能行之。」；第 7條第 1項第 2款：「年終
考績獎懲依左列規定︰二、乙等︰晉本俸一級，並給與半個月俸給總額之
一次獎金；已達所敘職等本俸最高俸級或已敘年功俸級者，晉年功俸一級，
並給與半個月俸給總額之一次獎金；已敘年功俸最高俸級者，給與一個半
月俸給總額之一次獎金。」；第 11 條第 1 項：「各機關參加考績人員任
本職等年終考績，具有左列各款情形之一者，取得同官等高一職等之任用
資格：一、二年列甲等者。二、一年列甲等二年列乙等者。」；第 14 條
第 1 項：「各機關對於公務人員之考績，應由主管人員就考績表項目評擬，
遞送考績委員會初核，機關長官覆核，經由主管機關或授權之所屬機關核
定，送銓敘部銓敘審定。……」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:06+00:00", "source_pdf_sha1": "e714802821e2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "102", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
